import { corsHeaders, jsonResponse } from '../_shared/cors.ts';
import { requireCrmAdmin } from '../_shared/supabase.ts';
import {
  assertMetaSendEnabled,
  BATCH_ALLOWED_MEDIA,
  formatError,
  MAX_BATCH_ATTACHMENTS,
  MAX_BATCH_BYTES,
  sendWhatsAppMediaOutbound,
  type MediaType,
} from '../_shared/whatsappOutbound.ts';
import { getStableKeyFromRecipient } from '../_shared/whatsappIdentity.ts';

interface BatchAttachment {
  clientAttachmentId: string;
  mediaType: MediaType;
  mediaUrl: string;
  storagePath?: string;
  filename?: string;
  mimeType?: string;
  sizeBytes?: number;
}

interface BatchResultItem {
  index: number;
  clientAttachmentId?: string;
  success: boolean;
  waMessageId?: string;
  logId?: string;
  error?: string;
}

function summarize(results: BatchResultItem[]) {
  const sent = results.filter((r) => r.success).length;
  const failed = results.length - sent;
  const status = sent === results.length
    ? 'completed'
    : sent > 0
      ? 'partial_failed'
      : 'failed';
  return { sent, failed, status: status as 'completed' | 'partial_failed' | 'failed' };
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const { supabase, user } = await requireCrmAdmin(req);
    const body = await req.json().catch(() => ({}));

    const to = String(body.to ?? '').trim();
    const clientBatchId = String(body.clientBatchId ?? '').trim();
    const phoneNumberId = body.phoneNumberId ? String(body.phoneNumberId).trim() : undefined;
    const caption = body.caption ? String(body.caption).trim() : undefined;
    const replyToWaMessageId = body.replyToWaMessageId
      ? String(body.replyToWaMessageId).trim()
      : undefined;
    const attachments = (body.attachments ?? []) as BatchAttachment[];

    if (!to) return jsonResponse({ error: 'Se requiere destinatario (to).' }, 400);
    if (!clientBatchId) return jsonResponse({ error: 'Se requiere clientBatchId.' }, 400);
    if (!Array.isArray(attachments) || attachments.length === 0) {
      return jsonResponse({ error: 'Se requiere al menos un adjunto.' }, 400);
    }
    if (attachments.length > MAX_BATCH_ATTACHMENTS) {
      return jsonResponse({ error: `Máximo ${MAX_BATCH_ATTACHMENTS} adjuntos por lote.` }, 400);
    }

    let totalBytes = 0;
    for (const [index, attachment] of attachments.entries()) {
      if (!attachment?.clientAttachmentId) {
        return jsonResponse({ error: `Adjunto ${index + 1}: falta clientAttachmentId.` }, 400);
      }
      if (!attachment.mediaUrl) {
        return jsonResponse({ error: `Adjunto ${index + 1}: falta mediaUrl.` }, 400);
      }
      if (!BATCH_ALLOWED_MEDIA.includes(attachment.mediaType)) {
        return jsonResponse({ error: `Adjunto ${index + 1}: tipo no soportado.` }, 400);
      }
      totalBytes += attachment.sizeBytes || 0;
    }
    if (totalBytes > MAX_BATCH_BYTES) {
      return jsonResponse({ error: 'El lote supera 100 MB.' }, 400);
    }

    const { data: existingBatch } = await supabase
      .from('whatsapp_outbound_batches')
      .select('*')
      .eq('client_batch_id', clientBatchId)
      .maybeSingle();

    if (existingBatch) {
      return jsonResponse({
        success: existingBatch.status === 'completed',
        batchId: clientBatchId,
        status: existingBatch.status,
        sent: existingBatch.sent,
        failed: existingBatch.failed,
        results: existingBatch.results ?? [],
        reused: true,
      });
    }

    try {
      assertMetaSendEnabled();
    } catch (error) {
      return jsonResponse({ error: String(error) }, 503);
    }

    await supabase.from('whatsapp_outbound_batches').insert({
      client_batch_id: clientBatchId,
      status: 'processing',
      to_key: getStableKeyFromRecipient(to),
      phone_number_id: phoneNumberId ?? null,
      total: attachments.length,
      sent: 0,
      failed: 0,
      results: [],
      created_by: user.id,
    });

    const results: BatchResultItem[] = [];

    for (const [index, attachment] of attachments.entries()) {
      try {
        const result = await sendWhatsAppMediaOutbound(supabase, {
          to,
          mediaType: attachment.mediaType,
          mediaUrl: attachment.mediaUrl,
          caption: index === 0 ? caption : undefined,
          filename: attachment.filename,
          replyToWaMessageId: index === 0 ? replyToWaMessageId : undefined,
          batchId: clientBatchId,
          batchIndex: index,
          clientAttachmentId: attachment.clientAttachmentId,
          storagePath: attachment.storagePath,
          mimeType: attachment.mimeType,
          sizeBytes: attachment.sizeBytes,
          phoneNumberId,
          agentUid: user.id,
        });

        results.push({
          index,
          clientAttachmentId: attachment.clientAttachmentId,
          success: result.success,
          waMessageId: result.waMessageId,
          logId: result.messageId,
          ...(result.error ? { error: result.error } : {}),
        });
      } catch (error) {
        results.push({
          index,
          clientAttachmentId: attachment.clientAttachmentId,
          success: false,
          error: formatError(error),
        });
      }

      const partial = summarize(results);
      await supabase.from('whatsapp_outbound_batches').update({
        status: 'processing',
        sent: partial.sent,
        failed: partial.failed,
        results,
      }).eq('client_batch_id', clientBatchId);
    }

    const summary = summarize(results);
    await supabase.from('whatsapp_outbound_batches').update({
      status: summary.status,
      sent: summary.sent,
      failed: summary.failed,
      results,
      completed_at: new Date().toISOString(),
    }).eq('client_batch_id', clientBatchId);

    return jsonResponse({
      success: summary.status === 'completed',
      batchId: clientBatchId,
      status: summary.status,
      sent: summary.sent,
      failed: summary.failed,
      results,
    });
  } catch (error) {
    if (error instanceof Response) return error;
    console.error('send-whatsapp-media-batch failed', error);
    return jsonResponse({ error: formatError(error) }, 500);
  }
});

export const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers':
    'authorization, x-client-info, apikey, content-type',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
};

export function jsonResponse(body: unknown, status = 200): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      ...corsHeaders,
      'Content-Type': 'application/json',
    },
  });
}

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

export function getServiceClient() {
  const supabaseUrl = Deno.env.get('SUPABASE_URL');
  const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

  if (!supabaseUrl || !serviceRoleKey) {
    throw new Error('Faltan SUPABASE_URL o SUPABASE_SERVICE_ROLE_KEY.');
  }

  return createClient(supabaseUrl, serviceRoleKey, {
    auth: {
      persistSession: false,
      autoRefreshToken: false,
    },
  });
}

export async function requireCrmAdmin(req: Request) {
  const authHeader = req.headers.get('Authorization');
  if (!authHeader) {
    throw new Response('Usuario no autenticado.', { status: 401 });
  }

  const supabase = getServiceClient();
  const token = authHeader.replace('Bearer ', '');
  const { data: userData, error: userError } = await supabase.auth.getUser(token);

  if (userError || !userData.user) {
    throw new Response('Usuario no autenticado.', { status: 401 });
  }

  const { data: profile, error: profileError } = await supabase
    .from('admin_profiles')
    .select('id,email,role,is_active')
    .eq('id', userData.user.id)
    .eq('is_active', true)
    .single();

  if (profileError || !profile || !['admin', 'super_admin'].includes(profile.role)) {
    throw new Response('Usuario sin permisos CRM.', { status: 403 });
  }

  return { supabase, user: userData.user, profile };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export const WHATSAPP_MEDIA_BUCKET = 'whatsapp-media';
export const DEFAULT_SIGNED_URL_EXPIRES_SECONDS = 15 * 60;
export const OUTBOUND_META_SIGNED_URL_EXPIRES_SECONDS = 7200;

export interface WhatsAppMediaBlob {
  bytes: Uint8Array;
  mimeType: string;
}

export interface PersistedWhatsAppMedia {
  storagePath: string;
  signedUrl: string;
  mimeType: string;
  fileSize: number;
}

export interface ExistingWhatsAppMediaAsset {
  bucketId: string;
  storagePath: string;
  mimeType: string | null;
  sizeBytes: number | null;
  messageLogId: string | null;
}

export function extensionFromMimeType(mimeType: string): string {
  const normalized = mimeType.toLowerCase();
  if (normalized.includes('jpeg') || normalized.includes('jpg')) return 'jpg';
  if (normalized.includes('png')) return 'png';
  if (normalized.includes('webp')) return 'webp';
  if (normalized.includes('ogg')) return 'ogg';
  if (normalized.includes('mpeg') || normalized.includes('mp3')) return 'mp3';
  if (normalized.includes('pdf')) return 'pdf';
  if (normalized.includes('mp4')) return 'mp4';
  if (normalized.includes('gif')) return 'gif';
  return 'bin';
}

export function buildStoragePath(
  stableKey: string,
  mediaId: string,
  mimeType: string,
): string {
  const ext = extensionFromMimeType(mimeType);
  return `${stableKey}/${mediaId}.${ext}`;
}

export function getWhatsAppAccessToken(): string | null {
  return Deno.env.get('WHATSAPP_ACCESS_TOKEN')?.trim() ?? null;
}

export async function downloadWhatsAppMediaFromMeta(
  mediaId: string,
  accessToken?: string,
): Promise<WhatsAppMediaBlob> {
  const token = accessToken ?? getWhatsAppAccessToken();
  if (!token) {
    throw new Error('WHATSAPP_ACCESS_TOKEN no configurado.');
  }

  const metaRes = await fetch(`https://graph.facebook.com/v21.0/${mediaId}`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  const metaJson = await metaRes.json().catch(() => ({}));
  if (!metaRes.ok) {
    const message =
      (metaJson as { error?: { message?: string } })?.error?.message ??
      `Meta media metadata failed (${metaRes.status})`;
    throw new Error(message);
  }

  const downloadUrl = String((metaJson as { url?: string }).url ?? '').trim();
  if (!downloadUrl) {
    throw new Error('URL de descarga Meta no disponible.');
  }

  const mimeType =
    String((metaJson as { mime_type?: string }).mime_type ?? '').trim() ||
    'application/octet-stream';

  const binaryRes = await fetch(downloadUrl, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!binaryRes.ok) {
    throw new Error(`No se pudo descargar media de Meta (${binaryRes.status}).`);
  }

  const bytes = new Uint8Array(await binaryRes.arrayBuffer());
  return {
    bytes,
    mimeType: binaryRes.headers.get('content-type')?.split(';')[0]?.trim() || mimeType,
  };
}

export async function createWhatsAppMediaSignedUrl(
  supabase: SupabaseClient,
  storagePath: string,
  expiresIn = DEFAULT_SIGNED_URL_EXPIRES_SECONDS,
  bucketId = WHATSAPP_MEDIA_BUCKET,
): Promise<string> {
  const { data, error } = await supabase.storage
    .from(bucketId)
    .createSignedUrl(storagePath, expiresIn);
  if (error || !data?.signedUrl) {
    throw error ?? new Error('No se pudo firmar URL de Storage.');
  }
  return data.signedUrl;
}

export async function persistToWhatsAppBucket(
  supabase: SupabaseClient,
  bytes: Uint8Array,
  storagePath: string,
  mimeType: string,
  expiresIn = DEFAULT_SIGNED_URL_EXPIRES_SECONDS,
): Promise<PersistedWhatsAppMedia> {
  const { error: uploadError } = await supabase.storage
    .from(WHATSAPP_MEDIA_BUCKET)
    .upload(storagePath, bytes, { upsert: true, contentType: mimeType });
  if (uploadError) {
    throw uploadError;
  }

  const signedUrl = await createWhatsAppMediaSignedUrl(
    supabase,
    storagePath,
    expiresIn,
  );

  return {
    storagePath,
    signedUrl,
    mimeType,
    fileSize: bytes.byteLength,
  };
}

export async function findExistingMediaAsset(
  supabase: SupabaseClient,
  mediaId: string,
): Promise<ExistingWhatsAppMediaAsset | null> {
  const { data: asset } = await supabase
    .from('whatsapp_media_assets')
    .select('bucket_id,storage_path,mime_type,size_bytes,message_log_id')
    .eq('media_id', mediaId)
    .order('created_at', { ascending: false })
    .limit(1)
    .maybeSingle();

  if (asset?.storage_path) {
    return {
      bucketId: String(asset.bucket_id ?? WHATSAPP_MEDIA_BUCKET),
      storagePath: String(asset.storage_path),
      mimeType: asset.mime_type ? String(asset.mime_type) : null,
      sizeBytes: typeof asset.size_bytes === 'number' ? asset.size_bytes : null,
      messageLogId: asset.message_log_id ? String(asset.message_log_id) : null,
    };
  }

  const { data: logRow } = await supabase
    .from('whatsapp_message_log')
    .select('id,storage_path,mime_type,size_bytes')
    .eq('media_id', mediaId)
    .not('storage_path', 'is', null)
    .order('created_at', { ascending: false })
    .limit(1)
    .maybeSingle();

  if (logRow?.storage_path) {
    return {
      bucketId: WHATSAPP_MEDIA_BUCKET,
      storagePath: String(logRow.storage_path),
      mimeType: logRow.mime_type ? String(logRow.mime_type) : null,
      sizeBytes: typeof logRow.size_bytes === 'number' ? logRow.size_bytes : null,
      messageLogId: logRow.id ? String(logRow.id) : null,
    };
  }

  return null;
}

export async function backfillInboundMediaRecords(params: {
  supabase: SupabaseClient;
  mediaId: string;
  storagePath: string;
  mimeType: string;
  fileSize: number;
  signedUrl: string;
}): Promise<void> {
  const { data: messages, error: messagesError } = await params.supabase
    .from('whatsapp_message_log')
    .select('id,storage_path')
    .eq('media_id', params.mediaId);

  if (messagesError) {
    console.error('[whatsappMediaStorage] backfill message lookup failed', {
      mediaId: params.mediaId,
      error: messagesError,
    });
    return;
  }

  for (const message of messages ?? []) {
    if (message.storage_path) continue;
    const { error: updateError } = await params.supabase
      .from('whatsapp_message_log')
      .update({
        storage_path: params.storagePath,
        storage_url: params.signedUrl,
        media_url: params.signedUrl,
        mime_type: params.mimeType,
        size_bytes: params.fileSize,
      })
      .eq('id', message.id);
    if (updateError) {
      console.error('[whatsappMediaStorage] backfill message update failed', {
        mediaId: params.mediaId,
        messageLogId: message.id,
        error: updateError,
      });
    }
  }

  const { data: existingAsset } = await params.supabase
    .from('whatsapp_media_assets')
    .select('id')
    .eq('media_id', params.mediaId)
    .limit(1)
    .maybeSingle();

  if (existingAsset?.id) return;

  const messageLogId =
    (messages ?? []).find((row) => row.id)?.id ??
    (await params.supabase
      .from('whatsapp_message_log')
      .select('id,conversation_stable_key')
      .eq('media_id', params.mediaId)
      .order('created_at', { ascending: false })
      .limit(1)
      .maybeSingle()).data?.id;

  const conversationStableKey = messageLogId
    ? (
        await params.supabase
          .from('whatsapp_message_log')
          .select('conversation_stable_key')
          .eq('id', messageLogId)
          .maybeSingle()
      ).data?.conversation_stable_key
    : null;

  if (!conversationStableKey) return;

  const { error: insertError } = await params.supabase.from('whatsapp_media_assets').insert({
    message_log_id: messageLogId,
    conversation_stable_key: conversationStableKey,
    bucket_id: WHATSAPP_MEDIA_BUCKET,
    storage_path: params.storagePath,
    media_id: params.mediaId,
    mime_type: params.mimeType,
    size_bytes: params.fileSize,
  });

  if (insertError) {
    console.error('[whatsappMediaStorage] backfill media asset insert failed', {
      mediaId: params.mediaId,
      error: insertError,
    });
  }
}

export async function resolveWhatsAppMediaById(params: {
  supabase: SupabaseClient;
  mediaId: string;
  stableKeyHint?: string;
  mimeTypeHint?: string | null;
  expiresIn?: number;
}): Promise<PersistedWhatsAppMedia> {
  const existing = await findExistingMediaAsset(params.supabase, params.mediaId);
  if (existing) {
    const signedUrl = await createWhatsAppMediaSignedUrl(
      params.supabase,
      existing.storagePath,
      params.expiresIn ?? DEFAULT_SIGNED_URL_EXPIRES_SECONDS,
      existing.bucketId,
    );
    return {
      storagePath: existing.storagePath,
      signedUrl,
      mimeType: existing.mimeType ?? params.mimeTypeHint ?? 'application/octet-stream',
      fileSize: existing.sizeBytes ?? 0,
    };
  }

  const { bytes, mimeType } = await downloadWhatsAppMediaFromMeta(params.mediaId);
  const storagePath = buildStoragePath(
    params.stableKeyHint?.trim() || 'unknown',
    params.mediaId,
    mimeType || params.mimeTypeHint || 'application/octet-stream',
  );

  const persisted = await persistToWhatsAppBucket(
    params.supabase,
    bytes,
    storagePath,
    mimeType,
    params.expiresIn ?? DEFAULT_SIGNED_URL_EXPIRES_SECONDS,
  );

  await backfillInboundMediaRecords({
    supabase: params.supabase,
    mediaId: params.mediaId,
    storagePath: persisted.storagePath,
    mimeType: persisted.mimeType,
    fileSize: persisted.fileSize,
    signedUrl: persisted.signedUrl,
  });

  return persisted;
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import {
  buildRecipientPayload,
  getBlocklistKey,
  getStableKeyFromRecipient,
  normalizePhone,
  resolveRecipient,
} from './whatsappIdentity.ts';
import {
  createWhatsAppMediaSignedUrl,
  OUTBOUND_META_SIGNED_URL_EXPIRES_SECONDS,
} from './whatsappMediaStorage.ts';

export type MediaType = 'image' | 'audio' | 'video' | 'document' | 'sticker';

export const WHATSAPP_API_VERSION = 'v21.0';
export const WHATSAPP_API_TIMEOUT_MS = 20000;
export const STATIC_STICKER_MAX_BYTES = 100 * 1024;
export const ANIMATED_STICKER_MAX_BYTES = 500 * 1024;
export const MAX_BATCH_ATTACHMENTS = 10;
export const MAX_BATCH_BYTES = 100 * 1024 * 1024;
export const BATCH_ALLOWED_MEDIA: MediaType[] = ['image', 'audio', 'video', 'document'];

export interface GraphCredentials {
  accessToken: string;
  phoneNumberId: string;
}

export interface MetaSendResult {
  status: 'sent' | 'failed';
  waMessageId: string | null;
  payload: Record<string, unknown>;
  logMessageBody: string;
  mediaType?: MediaType;
  mediaUrl?: string;
  caption?: string;
  filename?: string;
  errorMessage?: string;
}

export interface SendMediaOutboundParams {
  to: string;
  mediaType: MediaType;
  mediaUrl: string;
  caption?: string;
  filename?: string;
  replyToWaMessageId?: string;
  batchId?: string;
  batchIndex?: number;
  clientAttachmentId?: string;
  storagePath?: string;
  mimeType?: string;
  sizeBytes?: number;
  isAnimatedSticker?: boolean;
  phoneNumberId?: string;
  agentUid: string;
}

export interface SendMediaOutboundResult {
  success: boolean;
  waMessageId?: string;
  messageId?: string;
  createdAt?: string;
  error?: string;
}

export function formatError(error: unknown): string {
  if (error && typeof error === 'object') {
    const record = error as Record<string, unknown>;
    const parts = [record.message, record.details, record.hint]
      .filter((value) => typeof value === 'string' && value.length > 0);
    if (parts.length) return parts.join(' — ');
  }
  return String(error);
}

export function isUniqueViolation(error: unknown): boolean {
  return (
    typeof error === 'object' &&
    error !== null &&
    'code' in error &&
    (error as { code?: string }).code === '23505'
  );
}

export function isForeignKeyViolation(error: unknown): boolean {
  return (
    typeof error === 'object' &&
    error !== null &&
    'code' in error &&
    (error as { code?: string }).code === '23503'
  );
}

export function normalizeWaMessageId(value: string | null | undefined): string | null {
  const trimmed = value?.trim();
  return trimmed ? trimmed : null;
}

export function metaErrorMessage(payload: Record<string, unknown>): string | undefined {
  const metaResponse = payload.metaResponse as { error?: { message?: string; code?: number } } | undefined;
  return metaResponse?.error?.message;
}

export function metaErrorCode(payload: Record<string, unknown>): number | undefined {
  const metaResponse = payload.metaResponse as { error?: { code?: number } } | undefined;
  return metaResponse?.error?.code;
}

export function getGraphCredentials(phoneNumberIdOverride?: string): GraphCredentials {
  const accessToken = Deno.env.get('WHATSAPP_ACCESS_TOKEN')?.trim() ?? '';
  const phoneNumberId = (
    phoneNumberIdOverride?.trim() ||
    Deno.env.get('WHATSAPP_PHONE_NUMBER_ID')?.trim() ||
    ''
  );
  if (!accessToken || !phoneNumberId) {
    throw new Error('Credenciales WhatsApp incompletas (WHATSAPP_ACCESS_TOKEN y WHATSAPP_PHONE_NUMBER_ID).');
  }
  return { accessToken, phoneNumberId };
}

export function assertMetaSendEnabled(): void {
  const enabled = Deno.env.get('ENABLE_META_SEND')?.trim().toLowerCase() === 'true';
  if (!enabled) {
    throw new Error('Envio Meta desactivado. Configure ENABLE_META_SEND=true y secrets validos.');
  }
}

export async function isRecipientBlocked(
  supabase: SupabaseClient,
  to: string,
): Promise<boolean> {
  const key = getBlocklistKey(to);
  const { data } = await supabase
    .from('whatsapp_blocklist')
    .select('phone')
    .or(`phone.eq.${key},stable_key.eq.${key},bsuid.eq.${key}`)
    .maybeSingle();
  return Boolean(data);
}

function validateSticker(params: {
  caption?: string;
  filename?: string;
  mimeType?: string;
  sizeBytes?: number;
  isAnimatedSticker?: boolean;
}): string | null {
  if (params.caption || params.filename) {
    return 'Los stickers no admiten caption ni filename';
  }
  if (params.mimeType && params.mimeType !== 'image/webp') {
    return 'Los stickers deben ser image/webp';
  }
  if (typeof params.sizeBytes === 'number') {
    const maxBytes = params.isAnimatedSticker ? ANIMATED_STICKER_MAX_BYTES : STATIC_STICKER_MAX_BYTES;
    if (params.sizeBytes > maxBytes) {
      return params.isAnimatedSticker
        ? 'El sticker animado supera 500 KB'
        : 'El sticker estático supera 100 KB';
    }
  }
  return null;
}

export async function sendToMeta(params: {
  to: string;
  phoneNumberId: string;
  accessToken: string;
  messageBody?: string;
  mediaUrl?: string;
  mediaType?: MediaType;
  caption?: string;
  filename?: string;
  replyToWaMessageId?: string;
  templateName?: string;
  templateLanguage?: string;
  templateComponents?: unknown[];
  reactionToWaMessageId?: string;
  reactionEmoji?: string;
  requirePhone?: boolean;
}): Promise<MetaSendResult> {
  const recipient = resolveRecipient(params.to);
  const recipientPayload = buildRecipientPayload(recipient, {
    requirePhone: params.requirePhone,
  });

  let requestBody: Record<string, unknown>;

  if (params.reactionToWaMessageId !== undefined && params.reactionEmoji !== undefined) {
    requestBody = {
      messaging_product: 'whatsapp',
      ...recipientPayload,
      type: 'reaction',
      reaction: {
        message_id: params.reactionToWaMessageId,
        emoji: params.reactionEmoji,
      },
    };
  } else if (params.templateName) {
    requestBody = {
      messaging_product: 'whatsapp',
      ...recipientPayload,
      type: 'template',
      template: {
        name: params.templateName,
        language: { code: params.templateLanguage ?? 'es_CO' },
        ...(params.templateComponents?.length
          ? { components: params.templateComponents }
          : {}),
      },
    };
  } else if (params.mediaUrl && params.mediaType) {
    const mediaPayload: Record<string, unknown> = { link: params.mediaUrl };
    if (
      params.caption &&
      (params.mediaType === 'image' ||
        params.mediaType === 'video' ||
        params.mediaType === 'document')
    ) {
      mediaPayload.caption = params.caption;
    }
    if (params.mediaType === 'document' && params.filename) {
      mediaPayload.filename = params.filename;
    }
    requestBody = {
      messaging_product: 'whatsapp',
      ...recipientPayload,
      type: params.mediaType,
      [params.mediaType]: mediaPayload,
    };
  } else {
    requestBody = {
      messaging_product: 'whatsapp',
      ...recipientPayload,
      type: 'text',
      text: {
        preview_url: false,
        body: params.messageBody ?? '',
      },
    };
  }

  if (params.replyToWaMessageId) {
    requestBody.context = { message_id: params.replyToWaMessageId };
  }

  const response = await fetch(
    `https://graph.facebook.com/${WHATSAPP_API_VERSION}/${params.phoneNumberId}/messages`,
    {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${params.accessToken}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(requestBody),
      signal: AbortSignal.timeout(WHATSAPP_API_TIMEOUT_MS),
    },
  );

  const payload = await response.json().catch(() => ({}));
  const waMessageId = normalizeWaMessageId(
    Array.isArray(payload.messages) && payload.messages[0]?.id
      ? String(payload.messages[0].id)
      : null,
  );

  const logMessageBody = params.templateName
    ? (params.messageBody ?? `[Plantilla] ${params.templateName}`)
    : params.mediaUrl && params.mediaType
      ? params.caption || `[${params.mediaType}]`
      : params.reactionEmoji !== undefined
        ? params.reactionEmoji
        : (params.messageBody ?? '');

  return {
    status: response.ok && waMessageId ? 'sent' : 'failed',
    waMessageId,
    logMessageBody,
    mediaType: params.mediaType,
    mediaUrl: params.mediaUrl,
    caption: params.caption,
    filename: params.filename,
    errorMessage: metaErrorMessage({ metaResponse: payload }),
    payload: {
      metaStatus: response.status,
      metaOk: response.ok,
      metaResponse: payload,
    },
  };
}

export async function ensureConversation(
  supabase: SupabaseClient,
  stableKey: string,
  recipientPhone: string,
  phoneNumberId: string,
) {
  const { error } = await supabase.from('whatsapp_conversations').upsert(
    {
      stable_key: stableKey,
      phone: stableKey,
      contact_phone: recipientPhone,
      phone_number_id: phoneNumberId || null,
      state: 'active',
    },
    { onConflict: 'stable_key' },
  );
  if (error) throw error;
}

export async function persistOutboundLog(
  supabase: SupabaseClient,
  row: Record<string, unknown>,
  agentUid: string,
): Promise<{ messageId?: string; createdAt?: string }> {
  const baseRow = { ...row, agent_uid: agentUid };

  const attemptInsert = async (payload: Record<string, unknown>) =>
    supabase
      .from('whatsapp_message_log')
      .insert(payload)
      .select('id, created_at')
      .single();

  let { data: message, error: insertError } = await attemptInsert(baseRow);

  if (insertError && isForeignKeyViolation(insertError)) {
    ({ data: message, error: insertError } = await attemptInsert({ ...row, agent_uid: null }));
  }

  if (insertError) {
    const waMessageId = normalizeWaMessageId(row.wa_message_id as string | null | undefined);
    if (isUniqueViolation(insertError) && waMessageId) {
      const { data: existing } = await supabase
        .from('whatsapp_message_log')
        .select('id, created_at')
        .eq('wa_message_id', waMessageId)
        .maybeSingle();
      if (existing) {
        return { messageId: existing.id, createdAt: existing.created_at };
      }
    }
    throw insertError;
  }

  return {
    messageId: message?.id,
    createdAt: message?.created_at,
  };
}

export async function updateConversationPreview(
  supabase: SupabaseClient,
  stableKey: string,
  messageText: string,
  status: 'sent' | 'failed',
  createdAt: string,
) {
  const { error } = await supabase
    .from('whatsapp_conversations')
    .update({
      last_message_text: messageText,
      last_message_at: createdAt,
      last_message_direction: 'outbound',
      last_message_outbound_status: status,
      unread_count: 0,
    })
    .eq('stable_key', stableKey);

  if (error) console.error('updateConversationPreview failed', error);
}

export async function sendWhatsAppMediaOutbound(
  supabase: SupabaseClient,
  params: SendMediaOutboundParams,
): Promise<SendMediaOutboundResult> {
  assertMetaSendEnabled();
  const graph = getGraphCredentials(params.phoneNumberId);

  if (params.mediaType === 'sticker') {
    const stickerError = validateSticker(params);
    if (stickerError) return { success: false, error: stickerError };
  }

  if (await isRecipientBlocked(supabase, params.to)) {
    return { success: false, error: 'recipient_blocked' };
  }

  const stableKey = getStableKeyFromRecipient(params.to);
  const recipient = resolveRecipient(params.to);
  const recipientPhone = recipient.phone ? normalizePhone(recipient.phone) : stableKey;

  await ensureConversation(supabase, stableKey, recipientPhone, graph.phoneNumberId);

  let mediaUrlForMeta = params.mediaUrl;
  if (params.storagePath?.trim()) {
    mediaUrlForMeta = await createWhatsAppMediaSignedUrl(
      supabase,
      params.storagePath.trim(),
      OUTBOUND_META_SIGNED_URL_EXPIRES_SECONDS,
    );
  }

  const metaResult = await sendToMeta({
    to: params.to,
    phoneNumberId: graph.phoneNumberId,
    accessToken: graph.accessToken,
    mediaUrl: mediaUrlForMeta,
    mediaType: params.mediaType,
    caption: params.caption,
    filename: params.filename,
    replyToWaMessageId: params.replyToWaMessageId,
  });

  const insertRow: Record<string, unknown> = {
    conversation_stable_key: stableKey,
    recipient_phone: recipientPhone,
    recipient_bsuid: recipient.bsuid ?? null,
    direction: 'outbound',
    sender_type: 'agent',
    message_body: metaResult.logMessageBody,
    media_type: params.mediaType,
    media_url: mediaUrlForMeta,
    caption: params.caption ?? null,
    filename: params.filename ?? null,
    status: metaResult.status,
    wa_message_id: metaResult.waMessageId,
    reply_to_wa_message_id: params.replyToWaMessageId ?? null,
    campaign_type: 'OTHER',
    phone_number_id: graph.phoneNumberId,
    error_message: metaResult.errorMessage ?? null,
    raw_payload: metaResult.payload,
    batch_id: params.batchId ?? null,
    batch_index: typeof params.batchIndex === 'number' ? params.batchIndex : null,
    client_attachment_id: params.clientAttachmentId ?? null,
    storage_path: params.storagePath ?? null,
    mime_type: params.mimeType ?? null,
    size_bytes: typeof params.sizeBytes === 'number' ? params.sizeBytes : null,
    is_animated_sticker: params.isAnimatedSticker === true,
  };

  const persisted = await persistOutboundLog(supabase, insertRow, params.agentUid);
  const createdAt = persisted.createdAt ?? new Date().toISOString();

  await updateConversationPreview(
    supabase,
    stableKey,
    metaResult.logMessageBody,
    metaResult.status,
    createdAt,
  );

  if (metaResult.status === 'failed') {
    return {
      success: false,
      messageId: persisted.messageId,
      error: metaResult.errorMessage ?? 'Error al enviar con Meta.',
    };
  }

  return {
    success: true,
    waMessageId: metaResult.waMessageId ?? undefined,
    messageId: persisted.messageId,
    createdAt,
  };
}

